-- Superclass table
CREATE TABLE Person (
 person_id PRIMARY KEY,
 name VARCHAR(100),
 address VARCHAR(200),
 dob DATE
);

-- Subclass tables (inherit from Person)
CREATE TABLE Student (
 person_id PRIMARY KEY REFERENCES Person(person_id),
 student_id VARCHAR(20),
 department VARCHAR(50),
 semester INT
);

CREATE TABLE Teacher (
 person_id PRIMARY KEY REFERENCES Person(person_id),
 employee_id VARCHAR(20),
 salary DECIMAL(10,2),
 specialization VARCHAR(100)
);
